  // Wholesale
  const[isWholesale,setIsWholesale]=useState(false);
  const[showWholesaleModal,setShowWholesaleModal]=useState(false);

  // POS
  const[cart,setCart]=useState([]);
  const[filterCat,setFilterCat]=useState("全部");
  const[search,setSearch]=useState("");
  const[modal,setModal]=useState(null);
  const[lastOrder,setLastOrder]=useState(null);
  const[orderSearch,setOrderSearch]=useState("");
  const[expandedOrder,setExpandedOrder]=useState(null);

  // Products mgmt
  const[editingProduct,setEditingProduct]=useState(null);
  const[showAddForm,setShowAddForm]=useState(false);
  const[newProduct,setNewProduct]=useState({code:"",name:"",price:"",wholesale:"",category:"Activitae",stock:"99",image:"",desc:""});

  // Shop (customer)
  const[sfCart,setSfCart]=useState([]);
  const[sfCat,setSfCat]=useState("全部");
  const[sfSearch,setSfSearch]=useState("");
  const[sfModal,setSfModal]=useState(null);
  const[sfDetail,setSfDetail]=useState(null);
  const[sfCustomer,setSfCustomer]=useState({name:"",phone:"",note:"",address:"",deliveryType:"home",sfLocker:""});
  const[paymentMethod,setPaymentMethod]=useState("payme"); // payme or alipay
  const[sfOrderDone,setSfOrderDone]=useState(null);
  const[paymentImg,setPaymentImg]=useState("");
  const[sendingOrder,setSendingOrder]=useState(false);
  const[showMobileCart,setShowMobileCart]=useState(false);

  // VIP mode for customers
  const[isVIP,setIsVIP]=useState(false);
  const[showVIPModal,setShowVIPModal]=useState(false);
  const[showReturnPolicy,setShowReturnPolicy]=useState(false);
  const[showShippingInfo,setShowShippingInfo]=useState(false);

  // Banner editing
  const[editingBanners,setEditingBanners]=useState(false);
  const[localBanners,setLocalBanners]=useState([...DEFAULT_BANNERS]);

  const nextIdRef=useRef(51);

  useEffect(()=>{
    initProductsInDb();
    const u1=onSnapshot(collection(db,"products"),snap=>{
      setProducts(snap.docs.map(d=>({...d.data(),id:d.id})).sort((a,b)=>a.code>b.code?1:-1));
      setLoading(false);
    });
    const u2=onSnapshot(collection(db,"orders"),snap=>{
      setOrders(snap.docs.map(d=>({...d.data(),firestoreId:d.id})).sort((a,b)=>b.date>a.date?1:-1));
    });
    const u3=onSnapshot(doc(db,"settings","main"),snap=>{
      if(snap.exists()){
        const s=snap.data();
        if(s.banners&&s.banners.length>0){setBanners(s.banners);setLocalBanners(s.banners);}
      }
    });
    return()=>{u1();u2();u3();};
  },[]);

  const getPrice=p=>isWholesale?(p.wholesale||p.price):p.price;
  const posTotal=cart.reduce((s,i)=>s+i.usedPrice*i.qty,0);
  const sfTotal=sfCart.reduce((s,i)=>{
    const price=isVIP&&i.wholesale?i.wholesale:i.price;
    return s+price*i.qty;
  },0);
  const shippingFee = sfTotal > 0 && sfTotal < 500 ? 28 : 0;
  const sfTotalWithShipping = sfTotal + shippingFee;
  const pendingCount=orders.filter(o=>o.status==="待處理").length;

  const addToCart=p=>{
    const usedPrice=getPrice(p);
    setCart(prev=>{const ex=prev.find(i=>i.id===p.id);return ex?prev.map(i=>i.id===p.id?{...i,qty:i.qty+1}:i):[...prev,{...p,usedPrice,qty:1}];});
  };
  const updateQty=(id,d)=>setCart(prev=>prev.map(i=>i.id===id?{...i,qty:i.qty+d}:i).filter(i=>i.qty>0));
  const addToSfCart=p=>setSfCart(prev=>{const ex=prev.find(i=>i.id===p.id);return ex?prev.map(i=>i.id===p.id?{...i,qty:i.qty+1}:i):[...prev,{...p,qty:1}];});
  const updateSfQty=(id,d)=>setSfCart(prev=>prev.map(i=>i.id===id?{...i,qty:i.qty+d}:i).filter(i=>i.qty>0));

  const handleConfirm=async()=>{
    const order={items:cart.map(i=>({...i,price:i.usedPrice})),total:posTotal,date:new Date().toLocaleString("zh-HK"),orderNo:`ORD-${Date.now().toString().slice(-6)}`,source:"pos",customerName:"",customerPhone:"",status:"完成",priceType:isWholesale?"wholesale":"retail"};
    setLastOrder(order);await saveOrderToDb(order);setModal("receipt");
  };
  const handleDone=()=>{setCart([]);setModal(null);};

  const handleSfSubmit=async()=>{
    if(!paymentImg){alert("請先上傳付款截圖！");return;}
    if(!sfCustomer.name||!sfCustomer.phone){alert("請填寫姓名和電話！");return;}
    if(sfCustomer.deliveryType==="home"&&!sfCustomer.address){alert("請填寫郵寄地址！");return;}
    if(sfCustomer.deliveryType==="locker"&&!sfCustomer.sfLocker){alert("請選擇順豐智能櫃！");return;}
    
    setSendingOrder(true);
    const order={
      items:sfCart.map(i=>{
        const price=isVIP&&i.wholesale?i.wholesale:i.price;
        return {name:i.name,qty:i.qty,price:price,code:i.code,originalPrice:i.price,isVIP:isVIP&&i.wholesale?true:false};
      }),
      subtotal:sfTotal,
      shippingFee:shippingFee,
      total:sfTotalWithShipping,
      date:new Date().toLocaleString("zh-HK"),
      orderNo:`ONL-${Date.now().toString().slice(-6)}`,
      source:"online",
      customerName:sfCustomer.name,
      customerPhone:sfCustomer.phone,
      customerNote:sfCustomer.note,
      deliveryType:sfCustomer.deliveryType,
      deliveryAddress:sfCustomer.deliveryType==="home"?sfCustomer.address:sfCustomer.sfLocker,
      paymentMethod:paymentMethod,
      status:"待處理",
      priceType:isVIP?"vip":"retail",
      paymentImg
    };
    await saveOrderToDb(order);
    setSfOrderDone(order);setSfCart([]);setSfCustomer({name:"",phone:"",note:"",address:"",deliveryType:"home",sfLocker:""});setPaymentImg("");setPaymentMethod("payme");setSfModal("done");setSendingOrder(false);
  };

  const saveEdit=async()=>{setSaving(true);await saveProductToDb(editingProduct);setEditingProduct(null);setSaving(false);};
  const addProduct=async()=>{
    if(!newProduct.name||!newProduct.price)return;
    setSaving(true);
    const p={...newProduct,id:`p${nextIdRef.current++}`,price:parseFloat(newProduct.price)||0,wholesale:parseFloat(newProduct.wholesale)||0,stock:parseInt(newProduct.stock)||99};
    await saveProductToDb(p);
    setNewProduct({code:"",name:"",price:"",wholesale:"",category:"Activitae",stock:"99",image:"",desc:""});setShowAddForm(false);setSaving(false);
  };
  const deleteProduct=async id=>{if(!window.confirm("確認刪除？"))return;await deleteProductFromDb(id);};
  const markOrderDone=async order=>{const{firestoreId,...rest}=order;await setDoc(doc(db,"orders",firestoreId),{...rest,status:"已完成"});};
  const saveBanners=async()=>{await saveSettingsToDb({banners:localBanners});setBanners(localBanners);setEditingBanners(false);};

  const filtered=products.filter(p=>filterCat==="全部"||p.category===filterCat).filter(p=>!search||p.name.toLowerCase().includes(search.toLowerCase())||p.code.includes(search));
  const sfFiltered=products.filter(p=>sfCat==="全部"||p.category===sfCat).filter(p=>!sfSearch||p.name.toLowerCase().includes(sfSearch.toLowerCase()));
